import React, { useState, useEffect } from 'react';
import { Platform, Alert } from 'react-native';
import { RNIap, purchaseUpdatedListener, purchaseErrorListener, requestPurchase, getProducts, getSubscriptions, acknowledgePurchase, finishTransaction } from 'react-native-iap';
import { GooglePay } from 'react-native-google-pay';
import { ApplePay } from 'react-native-apple-pay';

const PaymentModule = () => {
  const [products, setProducts] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [isInitialized, setIsInitialized] = useState(false);

  useEffect(() => {
    initializePayment();
    return () => {
      if (purchaseUpdatedListener) purchaseUpdatedListener.remove();
      if (purchaseErrorListener) purchaseErrorListener.remove();
    };
  }, []);

  const initializePayment = async () => {
    try {
      await RNIap.initConnection();
      const products = await getProducts(['product_id']);
      const subscriptions = await getSubscriptions(['subscription_id']);
      setProducts(products);
      setSubscriptions(subscriptions);
      setIsInitialized(true);
    } catch (error) {
      console.error('Payment initialization failed:', error);
    }
  };

  const processPurchase = async (productId, paymentMethod) => {
    try {
      if (paymentMethod === 'apple_pay' && Platform.OS === 'ios') {
        const result = await ApplePay.requestPayment({
          amount: '10.00',
          currency: 'USD',
          merchantCapabilities: ['supports3DS'],
        });
        return result;
      } else if (paymentMethod === 'google_pay' && Platform.OS === 'android') {
        const result = await GooglePay.requestPayment({
          amount: '10.00',
          currency: 'USD',
        });
        return result;
      } else {
        const purchase = await requestPurchase(productId, false);
        return purchase;
      }
    } catch (error) {
      Alert.alert('Purchase Failed', error.message);
      throw error;
    }
  };

  const handlePurchaseSuccess = async (purchase) => {
    try {
      if (Platform.OS === 'ios') {
        await acknowledgePurchase(purchase.purchaseToken);
      }
      await finishTransaction(purchase.transactionId);
      return true;
    } catch (error) {
      console.error('Purchase confirmation failed:', error);
      return false;
    }
  };

  const processWalletTransaction = async (amount, currency, walletProvider) => {
    try {
      if (walletProvider === 'google_pay') {
        const result = await GooglePay.requestPayment({
          amount: amount.toString(),
          currency: currency,
        });
        return result;
      } else if (walletProvider === 'apple_pay') {
        const result = await ApplePay.requestPayment({
          amount: amount.toString(),
          currency: currency,
        });
        return result;
      }
    } catch (error) {
      Alert.alert('Wallet Transaction Failed', error.message);
      throw error;
    }
  };

  const validatePaymentData = (data) => {
    const requiredFields = ['amount', 'currency', 'paymentMethod'];
    return requiredFields.every(field => data[field] !== undefined);
  };

  const secureEncrypt = (data) => {
    return Buffer.from(JSON.stringify(data)).toString('base64');
  };

  const secureDecrypt = (encryptedData) => {
    return JSON.parse(Buffer.from(encryptedData, 'base64').toString('utf8'));
  };

  return {
    products,
    subscriptions,
    isInitialized,
    processPurchase,
    handlePurchaseSuccess,
    processWalletTransaction,
    validatePaymentData,
    secureEncrypt,
    secureDecrypt,
  };
};

export default PaymentModule;